#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        long long oddCount = 0, sum = 0;
        for(int i=0;i<N;i++){
            long long x; scanf("%lld", &x);
            sum += x;
            if(x & 1LL) oddCount++;
        }
        long long target = sum & 1LL;
        long long ans = (oddCount - target) / 2;
        printf("%lld\n", ans);
    }
    return 0;
}

